import requests

# 获取当前时间
def get_url_time():
    from datetime import datetime, timezone
    from urllib.parse import quote

    # 获取当前UTC时间，格式：2026-06-10T03:34:17Z
    now_utc = datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")

    # URL编码（冒号: → %3A）
    result = quote(now_utc)

    print(result)
    return result

